'use client'

import { useState, useEffect, useRef } from 'react'
import Link from 'next/link'
import { ChevronLeft, ChevronRight } from 'lucide-react'

/* --- FIXED IMPORT (Matches your new filename) --- */
import FloatingImp from '../layout/Floatingimp'

import '../../styles/Sports-grid.css'

const STREAMED_API_BASE = process.env.NEXT_PUBLIC_STREAMED_API_BASE_URL || 'https://streamed.pk/api'

// --- ICONS & CONFIG ---
const sportIcons: Record<string, string> = {
  football: '⚽', americanfootball: '🏈', basketball: '🏀', baseball: '⚾',
  hockey: '🏒', tennis: '🎾', mma: '🥊', boxing: '🥊', cricket: '🏏',
  rugby: '🏉', motorsport: '🏁', motorsports: '🏎️', volleyball: '🏐',
  golf: '⛳', darts: '🎯',
}

const sportNames: Record<string, string> = {
  football: 'Soccer', americanfootball: 'Football', basketball: 'Basketball',
  baseball: 'Baseball', hockey: 'Ice Hockey', tennis: 'Tennis',
  mma: 'MMA / UFC', boxing: 'Boxing', cricket: 'Cricket', rugby: 'Rugby',
  motorsport: 'F1/MotoGP', racing: 'Auto Racing', volleyball: 'Volleyball',
  golf: 'Golf', darts: 'Darts',
}

function normalizeSportKey(sportName: string) {
  if (!sportName) return ''
  return sportName.toLowerCase().replace(/\s+/g, '').replace(/[()]/g, '')
}

function getSportIcon(sportName: string) {
  const normalizedKey = normalizeSportKey(sportName)
  if (normalizedKey.includes('fight')) return sportIcons.mma
  return sportIcons[normalizedKey] || undefined
}

function getDisplaySportName(sport: string) {
  const normalizedKey = normalizeSportKey(sport)
  if (normalizedKey.includes('fight')) return sportNames.mma
  return sportNames[normalizedKey] || sport.charAt(0).toUpperCase() + sport.slice(1)
}

function hasMatchStarted(dateString: string) {
  try {
    const matchTime = new Date(dateString)
    const currentTime = new Date()
    return matchTime <= currentTime
  } catch {
    return false
  }
}

export default function SportsGrid() {
  const [sports, setSports] = useState<any[]>([])
  const [loading, setLoading] = useState(true)
  const containerRef = useRef<HTMLDivElement>(null)

  useEffect(() => {
    async function loadSports() {
      try {
        const res = await fetch(`${STREAMED_API_BASE}/sports`)
        const sportsData = await res.json()

        const sportsWithCounts = await Promise.all(
          sportsData.map(async (sport: any) => {
            try {
              const matchesRes = await fetch(`${STREAMED_API_BASE}/matches/${sport.id}`)
              if (!matchesRes.ok) return { ...sport, matchCount: 0 }
              const matches = await matchesRes.json()
              const liveMatches = Array.isArray(matches) 
                ? matches.filter((m: any) => m.sources?.length > 0 && hasMatchStarted(m.date))
                : []
              return { ...sport, matchCount: liveMatches.length }
            } catch {
              return { ...sport, matchCount: 0 }
            }
          })
        )
        setSports(sportsWithCounts)
      } catch (error) {
        console.error('Failed to load sports', error)
      } finally {
        setLoading(false)
      }
    }
    loadSports()
  }, [])

  const scroll = (direction: 'left' | 'right') => {
    if (containerRef.current) {
      const scrollAmount = 350
      containerRef.current.scrollBy({
        left: direction === 'left' ? -scrollAmount : scrollAmount,
        behavior: 'smooth'
      })
    }
  }

  // --- SKELETON LOADING STATE ---
  if (loading) {
    return (
      <section className="sports-section">
        <div className="section-header">
          <div className="title-group">
            <div className="skeleton-title-bar skeleton-shimmer"></div>
            <div className="title-accent"></div>
          </div>
          <div className="nav-controls">
            <div className="skeleton-nav-btn skeleton-shimmer"></div>
            <div className="skeleton-nav-btn skeleton-shimmer"></div>
          </div>
        </div>

        <div className="sports-carousel-container" style={{ overflow: 'hidden' }}>
          {[...Array(10)].map((_, i) => (
            <div key={i} className="skeleton-card"></div>
          ))}
        </div>
      </section>
    )
  }

  return (
    <>
    <FloatingImp />
    
    <section className="sports-section">
      
      {/* HEADER */}
      <div className="section-header">
        <div className="title-group">
          <h2 className="section-title">Sports</h2>
          <div className="title-accent"></div>
        </div>

        <div className="nav-controls">
          <button 
            className="nav-btn" 
            onClick={() => scroll('left')}
            aria-label="Scroll Left"
          >
            <ChevronLeft width={20} />
          </button>
          <button 
            className="nav-btn" 
            onClick={() => scroll('right')}
            aria-label="Scroll Right"
          >
            <ChevronRight width={20} />
          </button>
        </div>
      </div>

      {/* CAROUSEL */}
      <div className="carousel-wrapper">
        <div className="sports-carousel-container" ref={containerRef}>
          {sports.map((sport: any) => {
            const icon = getSportIcon(sport.name)
            const displayName = getDisplaySportName(sport.name)
            const isLive = sport.matchCount > 0
            
            if (!icon) return null
            
            return (
              <Link 
                key={sport.id}
                href={`/live-matches?sportId=${sport.id}&sportName=${encodeURIComponent(sport.name)}`}
                className="sport-card-link"
              >
                <div className={`sport-card ${isLive ? 'active-live' : ''}`}>
                  <div className="card-icon-wrapper">
                      <span className="sport-emoji">{icon}</span>
                  </div>
                  
                  <div className="card-content">
                      <h3 className="sport-title">{displayName}</h3>
                      
                      <div className={`match-badge ${isLive ? 'live' : 'offline'}`}>
                          {isLive && <span className="live-dot"></span>}
                          {sport.matchCount} Live
                      </div>
                  </div>
                </div>
              </Link>
            )
          })}
        </div>
      </div>
    </section>
    </>
  )
}